import { NextResponse } from 'next/server';

export async function GET(request: Request) {
  const { searchParams } = new URL(request.url);
  const targetUrl = searchParams.get('url');

  if (!targetUrl) return new NextResponse('Missing URL', { status: 400 });

  try {
    // 1. Fetch the dirty HTML
    const res = await fetch(targetUrl, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Referer': 'https://streamed.pk/' 
      }
    });

    if (!res.ok) throw new Error(`Upstream Error: ${res.status}`);

    let html = await res.text();
    const origin = new URL(targetUrl).origin; // e.g. https://embedsports.top

    // 2. THE BRUTE FORCE FIX (Fixes the 404s)
    // We physically replace "/js/" with "https://embedsports.top/js/"
    // We check both double quotes and single quotes
    html = html.replaceAll('src="/', `src="${origin}/`);
    html = html.replaceAll('src=\'/', `src='${origin}/`);
    html = html.replaceAll('href="/', `href="${origin}/`);
    html = html.replaceAll('href=\'/', `href='${origin}/`);
    
    // Also fix the specific dynamic script loader we saw in your source
    html = html.replaceAll('setAttribute("src", "/', `setAttribute("src", "${origin}/`);

    // 3. THE SURGERY (Kill Popups)
    // Kill the specific popup function
    html = html.replace(/aclib\.runPop/g, 'console.log("Popup blocked"); //');
    
    // Nuclear Option: Overwrite window.open so NO script can open tabs
    const killScript = `<script>window.open = function(){ console.log("Window.open killed!"); return null; };</script>`;
    if (html.includes('<head>')) {
        html = html.replace('<head>', `<head>${killScript}`);
    } else {
        html = killScript + html;
    }

    // 4. Return Clean HTML
    return new NextResponse(html, {
      headers: { 'Content-Type': 'text/html' }
    });

  } catch (error) {
    console.error('Janitor Error:', error);
    return new NextResponse('Stream Unavailable', { status: 500 });
  }
}